import React, { useState, useEffect, useRef, useCallback } from 'react';
import { MapContainer, TileLayer, GeoJSON, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { useAuth } from '../context/AuthContext';
import { usePanchayat } from '../context/PanchayatContext';
import { getMapSensors, getMapReadings } from '../api';
import { getSensorColor, getSensorLabel, SENSOR_LEGENDS } from '../utils/sensorColors';
import { Layers, RefreshCw, ChevronLeft, Loader, Cpu, AlertCircle } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

const SENSOR_TYPES = ['Temp', 'WaterPH', 'WaterSalinity', 'SoilMoisture', 'SoilPH', 'AirQuality'];

// Creates SVG pin marker with color
function createPinIcon(color, value, type) {
  const label = value != null ? getSensorLabel(type, value) : '?';
  const svg = `
    <svg xmlns="http://www.w3.org/2000/svg" width="44" height="56" viewBox="0 0 44 56">
      <filter id="shadow">
        <feDropShadow dx="0" dy="2" stdDeviation="2" flood-opacity="0.4"/>
      </filter>
      <path d="M22 2 C12 2 4 10 4 20 C4 34 22 54 22 54 C22 54 40 34 40 20 C40 10 32 2 22 2Z"
        fill="${color}" stroke="white" stroke-width="2" filter="url(#shadow)"/>
      <circle cx="22" cy="20" r="10" fill="white" opacity="0.9"/>
      <text x="22" y="24" text-anchor="middle" 
        font-family="monospace" font-size="7" font-weight="bold" fill="${color}">
        ${label.length > 7 ? label.slice(0, 7) : label}
      </text>
    </svg>
  `;
  return L.divIcon({
    html: svg,
    className: '',
    iconSize: [44, 56],
    iconAnchor: [22, 54],
    popupAnchor: [0, -54],
  });
}

// Mask layer — darkens outside the boundary
function BoundaryMask({ geoJson, targetFeature }) {
  const map = useMap();

  useEffect(() => {
    if (!geoJson || !targetFeature) return;

    // World bounds polygon
    const world = [[-90, -180], [-90, 180], [90, 180], [90, -180], [-90, -180]];

    // The boundary layer with inverted mask effect
    const boundaryLayer = L.geoJSON(targetFeature, {
      style: {
        color: '#ef4444',
        weight: 2.5,
        opacity: 1,
        fillOpacity: 0,
      },
    }).addTo(map);

    // Dark overlay for outside - use a large rectangle minus the feature
    const maskLayer = L.geoJSON({
      type: 'Feature',
      geometry: {
        type: 'Polygon',
        coordinates: [world],
      },
    }, {
      style: {
        color: 'transparent',
        fillColor: '#030712',
        fillOpacity: 0.65,
      },
      interactive: false,
    }).addTo(map);

    // Bring boundary on top
    boundaryLayer.bringToFront();

    return () => {
      map.removeLayer(boundaryLayer);
      map.removeLayer(maskLayer);
    };
  }, [geoJson, targetFeature, map]);

  return null;
}

// Fit map to boundary
function FitBounds({ feature }) {
  const map = useMap();
  useEffect(() => {
    if (!feature) return;
    try {
      const layer = L.geoJSON(feature);
      map.fitBounds(layer.getBounds(), { padding: [40, 40] });
    } catch {}
  }, [feature, map]);
  return null;
}

export default function MapPage() {
  const { user } = useAuth();
  const { selectedDistrict, selectedPanchayat } = usePanchayat();
  const navigate = useNavigate();

  const [selectedType, setSelectedType] = useState('Temp');
  const [sensors, setSensors] = useState([]);
  const [readings, setReadings] = useState({});
  const [geoJson, setGeoJson] = useState(null);
  const [targetFeature, setTargetFeature] = useState(null);
  const [loading, setLoading] = useState(false);
  const [loadingReadings, setLoadingReadings] = useState(false);
  const [error, setError] = useState('');

  // Load GeoJSON file
  useEffect(() => {
    fetch('/kerala.geojson')
      .then(r => r.json())
      .then(data => setGeoJson(data))
      .catch(() => setError('Failed to load boundary data'));
  }, []);

  // Determine which boundary feature to highlight based on role
  useEffect(() => {
    if (!geoJson) return;

    if (user.role === 'state') {
      // Use all of Kerala — merge all features or use a Kerala boundary feature
      setTargetFeature({
        type: 'FeatureCollection',
        features: geoJson.features,
      });
    } else {
      // For district/block/panchayat, highlight the district boundary
      const districtName = selectedDistrict?.name || user.location_name;
      if (!districtName) return;

      const feature = geoJson.features.find(f =>
        f.properties?.district?.toLowerCase() === districtName.toLowerCase() ||
        f.properties?.NAME_2?.toLowerCase() === districtName.toLowerCase() ||
        f.properties?.name?.toLowerCase() === districtName.toLowerCase()
      );
      setTargetFeature(feature || null);
    }
  }, [geoJson, user, selectedDistrict]);

  // Load sensors when type changes
  const loadSensors = useCallback(async () => {
    setLoading(true);
    setError('');
    setSensors([]);
    setReadings({});
    try {
      const data = await getMapSensors(selectedType);
      setSensors(data);

      // Fetch live readings for all sensors
      if (data.length > 0) {
        setLoadingReadings(true);
        const readingData = await getMapReadings(
          data.map(s => ({ id: s.id, type: s.type, district_name: s.district_name }))
        );
        setReadings(readingData);
        setLoadingReadings(false);
      }
    } catch (err) {
      setError('Failed to load sensor data');
    } finally {
      setLoading(false);
    }
  }, [selectedType]);

  useEffect(() => {
    loadSensors();
  }, [loadSensors]);

  // Auto-refresh readings every 15 seconds
  useEffect(() => {
    if (!sensors.length) return;
    const interval = setInterval(async () => {
      try {
        const readingData = await getMapReadings(
          sensors.map(s => ({ id: s.id, type: s.type, district_name: s.district_name }))
        );
        setReadings(readingData);
      } catch {}
    }, 15000);
    return () => clearInterval(interval);
  }, [sensors]);

  const roleLabel = {
    state: 'Kerala (State View)',
    district: selectedDistrict?.name || user.location_name,
    block: user.location_name,
    panchayat: user.location_name,
  }[user.role];

  const legend = SENSOR_LEGENDS[selectedType] || [];

  return (
    <div className="h-screen flex flex-col bg-gray-950">
      {/* Top bar */}
      <div className="flex-shrink-0 flex items-center gap-4 px-4 py-3 bg-gray-900 border-b border-gray-800">
        <button
          onClick={() => navigate('/dashboard')}
          className="flex items-center gap-1.5 text-sm text-gray-400 hover:text-white transition-colors"
        >
          <ChevronLeft className="w-4 h-4" /> Dashboard
        </button>

        <div className="flex items-center gap-2">
          <Layers className="w-4 h-4 text-green-400" />
          <span className="text-sm font-semibold text-white">Sensor Map</span>
          <span className="text-xs text-gray-500">— {roleLabel}</span>
        </div>

        <div className="ml-auto flex items-center gap-3">
          {/* Type selector */}
          <select
            value={selectedType}
            onChange={e => setSelectedType(e.target.value)}
            className="bg-gray-800 border border-gray-700 text-gray-100 text-sm rounded-lg px-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-green-500"
          >
            {SENSOR_TYPES.map(t => <option key={t} value={t}>{t}</option>)}
          </select>

          <button
            onClick={loadSensors}
            disabled={loading}
            className="flex items-center gap-1.5 text-sm text-gray-400 hover:text-white transition-colors disabled:opacity-50"
          >
            <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} />
            Refresh
          </button>

          <div className="flex items-center gap-1.5 text-xs text-gray-500">
            <Cpu className="w-3.5 h-3.5" />
            {loading ? '...' : `${sensors.length} sensors`}
          </div>
        </div>
      </div>

      {/* Map + overlay */}
      <div className="flex-1 relative">
        {error && (
          <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2 bg-red-900/90 border border-red-700 text-red-300 px-4 py-2 rounded-lg text-sm">
            <AlertCircle className="w-4 h-4" /> {error}
          </div>
        )}

        {loading && (
          <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2 bg-gray-900/95 border border-gray-700 text-gray-300 px-4 py-2 rounded-lg text-sm">
            <Loader className="w-4 h-4 animate-spin text-green-400" />
            Loading sensors...
          </div>
        )}

        {loadingReadings && !loading && (
          <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2 bg-gray-900/95 border border-gray-700 text-gray-300 px-4 py-2 rounded-lg text-sm">
            <Loader className="w-4 h-4 animate-spin text-green-400" />
            Fetching live readings...
          </div>
        )}

        <MapContainer
          center={[10.5, 76.27]}
          zoom={9}
          className="w-full h-full"
          zoomControl={true}
        >
          <TileLayer
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
          />

          {targetFeature && (
            <>
              <BoundaryMask geoJson={geoJson} targetFeature={targetFeature} />
              <FitBounds feature={targetFeature} />
            </>
          )}

          {/* Sensor pins */}
          {sensors.map(sensor => {
            const value = readings[sensor.id] ?? null;
            const color = getSensorColor(selectedType, value);
            const icon = createPinIcon(color, value, selectedType);

            return (
              <Marker
                key={sensor.id}
                position={[sensor.latitude, sensor.longitude]}
                icon={icon}
              >
                <Popup className="sensor-popup">
                  <div className="min-w-[200px] font-sans">
                    {/* Popup header */}
                    <div className="flex items-center gap-2 mb-2 pb-2 border-b border-gray-200">
                      <div
                        className="w-3 h-3 rounded-full flex-shrink-0"
                        style={{ backgroundColor: color }}
                      />
                      <span className="font-bold text-gray-800 text-sm">{sensor.id}</span>
                    </div>

                    {/* Reading */}
                    <div className="text-center py-2 mb-2 rounded-lg" style={{ backgroundColor: color + '20' }}>
                      <div className="text-2xl font-bold" style={{ color }}>
                        {value != null ? getSensorLabel(selectedType, value) : 'No data'}
                      </div>
                      <div className="text-xs text-gray-500 mt-0.5">{selectedType}</div>
                    </div>

                    {/* Details */}
                    <table className="w-full text-xs text-gray-600">
                      <tbody>
                        {sensor.name && (
                          <tr><td className="font-medium pr-2 py-0.5">Name</td><td>{sensor.name}</td></tr>
                        )}
                        <tr><td className="font-medium pr-2 py-0.5">Status</td>
                          <td><span className={`font-medium ${sensor.status === 'active' ? 'text-green-600' : 'text-gray-400'}`}>{sensor.status}</span></td>
                        </tr>
                        {sensor.villager_name && (
                          <tr><td className="font-medium pr-2 py-0.5">Villager</td><td>{sensor.villager_name}</td></tr>
                        )}
                        {sensor.panchayat_name && (
                          <tr><td className="font-medium pr-2 py-0.5">Panchayat</td><td>{sensor.panchayat_name}</td></tr>
                        )}
                        {sensor.location_description && (
                          <tr><td className="font-medium pr-2 py-0.5">Location</td><td>{sensor.location_description}</td></tr>
                        )}
                        <tr>
                          <td className="font-medium pr-2 py-0.5">GPS</td>
                          <td className="font-mono">{sensor.latitude?.toFixed(4)}, {sensor.longitude?.toFixed(4)}</td>
                        </tr>
                      </tbody>
                    </table>

                    <div className="mt-2 pt-2 border-t border-gray-200 text-xs text-gray-400 text-center">
                      Auto-refreshes every 15s
                    </div>
                  </div>
                </Popup>
              </Marker>
            );
          })}
        </MapContainer>

        {/* Legend */}
        <div className="absolute bottom-6 right-4 z-40 bg-gray-900/95 border border-gray-700 rounded-xl p-3 min-w-[160px]">
          <div className="text-xs font-semibold text-gray-300 uppercase tracking-wider mb-2">
            {selectedType} Legend
          </div>
          <div className="space-y-1.5">
            {legend.map((item, i) => (
              <div key={i} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full flex-shrink-0" style={{ backgroundColor: item.color }} />
                <span className="text-xs text-gray-400">{item.label}</span>
              </div>
            ))}
            <div className="flex items-center gap-2 pt-1 border-t border-gray-700 mt-1">
              <div className="w-3 h-3 rounded-full flex-shrink-0 bg-gray-500" />
              <span className="text-xs text-gray-500">No data</span>
            </div>
          </div>
        </div>

        {/* Role badge */}
        <div className="absolute top-4 left-4 z-40 bg-gray-900/95 border border-gray-700 rounded-lg px-3 py-1.5">
          <div className="text-xs text-gray-400 capitalize">{user.role} view</div>
          <div className="text-sm font-semibold text-white">{roleLabel}</div>
        </div>
      </div>
    </div>
  );
}
